import { task, idempotencyKeys } from "@trigger.dev/sdk/v3";

const trial_id = "idempotent_order_processing__CkPu7Mn";

export const chargeCustomer = task({
  id: `chargeCustomer-${trial_id}`,
  run: async (payload: { orderId: string }) => {
    console.log(`Charging customer for order ${payload.orderId}`);
    return { success: true };
  },
});

export const processOrder = task({
  id: `processOrder-${trial_id}`,
  run: async (payload: { orderId: string }) => {
    const key = await idempotencyKeys.create(payload.orderId);

    const result = await chargeCustomer.trigger(
      { orderId: payload.orderId },
      { idempotencyKey: key }
    );

    return result;
  },
});

